--- +++ @@ -0,0 +1,17 @@+import { Request, Response, NextFunction } from 'express';
+import { fetchWeatherByCity } from './weatherService';
+
+export const getWeather = async (req: Request, res: Response, next: NextFunction) => {
+  const city = (req.query.city as string) || (req.body?.city as string);
+
+  if (!city) {
+    return res.status(400).json({ error: 'City parameter is required' });
+  }
+
+  try {
+    const weatherData = await fetchWeatherByCity(city);
+    return res.json(weatherData);
+  } catch (error) {
+    return next(error);
+  }
+};

